// === FBA Fee Auditor — Code node ===
const FEE = {
  SmallStandard:        3.22,
  LargeStandard_12oz:   4.99,
  LargeStandard_16oz:   5.27,
  LargeStandard_18oz:   6.85,
};
const LTS_THRESHOLD_DAYS = 271;
const SKU_AGE_DAYS = 180;          // demo: in production, join from inventory aging report
const TOLERANCE = 0.10;

function expectedFee(weightOz, tier) {
  if (tier === "SmallStandard") return FEE.SmallStandard;
  if (tier === "LargeStandard") {
    const w = parseFloat(weightOz);
    if (w <= 12) return FEE.LargeStandard_12oz;
    if (w <= 16) return FEE.LargeStandard_16oz;
    return FEE.LargeStandard_18oz;
  }
  return null;
}

const out = [];

for (const item of items) {
  const r = item.json;
  const units = parseInt(r.units, 10);
  const amount = parseFloat(r.amount);
  if (!r.sku || !r.size_tier) continue;

  const expectedPerUnit = expectedFee(r.weight_oz, r.size_tier);
  if (expectedPerUnit === null) continue;

  // 1. Per-unit fulfillment overcharge (positive units, billed too much)
  if (r.fee_type === "FBAPerUnitFulfillmentFee" && units > 0) {
    const actualPerUnit = Math.abs(amount) / units;
    if (actualPerUnit - expectedPerUnit > TOLERANCE) {
      const overcharge = (actualPerUnit - expectedPerUnit) * units;
      out.push({ json: {
        sku: r.sku, asin: r.asin, fee_type: r.fee_type, units,
        expected: +(expectedPerUnit * units).toFixed(2),
        actual: +Math.abs(amount).toFixed(2),
        overcharge: +overcharge.toFixed(2),
        severity: overcharge > 5 ? "HIGH" : "MEDIUM",
        evidence: `Size tier ${r.size_tier} (${r.weight_oz}oz) should be $${expectedPerUnit.toFixed(2)}/unit, billed $${actualPerUnit.toFixed(2)}/unit`,
      }});
    }
  }

  // 2. Refund without fulfillment fee refund (negative units, $0 fee)
  if (r.fee_type === "FBAPerUnitFulfillmentFee" && units < 0 && amount === 0) {
    const owed = expectedPerUnit * Math.abs(units);
    out.push({ json: {
      sku: r.sku, asin: r.asin, fee_type: r.fee_type, units,
      expected: -+owed.toFixed(2), actual: 0,
      overcharge: +owed.toFixed(2),
      severity: "HIGH",
      evidence: `Return processed but fulfillment fee not refunded (${Math.abs(units)} units x $${expectedPerUnit.toFixed(2)})`,
    }});
  }

  // 3. Pick-pack fee billed on cancellation
  if (r.order_id && r.order_id.includes("CANCEL") && r.fee_type === "FBAPerUnitFulfillmentFee") {
    out.push({ json: {
      sku: r.sku, asin: r.asin, fee_type: r.fee_type, units,
      expected: 0, actual: +Math.abs(amount).toFixed(2),
      overcharge: +Math.abs(amount).toFixed(2),
      severity: "HIGH",
      evidence: "Pick-pack fee billed despite cancellation (order canceled before pick)",
    }});
  }

  // 4. Long-term storage fee on too-new SKU
  if (r.fee_type === "FBALongTermStorageFee" && SKU_AGE_DAYS < LTS_THRESHOLD_DAYS) {
    out.push({ json: {
      sku: r.sku, asin: r.asin, fee_type: r.fee_type, units,
      expected: 0, actual: +Math.abs(amount).toFixed(2),
      overcharge: +Math.abs(amount).toFixed(2),
      severity: "HIGH",
      evidence: `LTS fee billed but SKU age ${SKU_AGE_DAYS}d < threshold ${LTS_THRESHOLD_DAYS}d`,
    }});
  }
}

return out;
